import{_ as t,o as s,c as a,ai as r}from"./chunks/framework.Bke2s2V8.js";const u=JSON.parse('{"title":"Le génitif","description":"","frontmatter":{},"headers":[],"relativePath":"module-5-aller-plus-loin/genitif.md","filePath":"module-5-aller-plus-loin/genitif.md","lastUpdated":1773298982000}'),l={name:"module-5-aller-plus-loin/genitif.md"};function i(n,e,o,d,c,m){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="le-genitif" tabindex="-1">Le génitif <a class="header-anchor" href="#le-genitif" aria-label="Permalink to “Le génitif”">​</a></h1><p><strong>Prérequis :</strong> <a href="./konjunktiv-2.html">Le Konjunktiv II</a></p><p><strong>Objectif :</strong> reconnaitre et utiliser le genitif - le cas de la possession et de certaines prépositions.</p><p>Le genitif est le quatrième et dernier cas de l&#39;allemand. Il exprime principalement la possession. À l&#39;oral courant, il est souvent remplacé par <em>von + datif</em>, mais il reste indispensable à l&#39;écrit et dans les registres soignes.</p><h2 id="les-articles-au-genitif" tabindex="-1">Les articles au genitif <a class="header-anchor" href="#les-articles-au-genitif" aria-label="Permalink to “Les articles au genitif”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600"></th><th class="p-3 text-center font-semibold text-blue-700">Masculin</th><th class="p-3 text-center font-semibold text-red-600">Féminin</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th><th class="p-3 text-center font-semibold text-gray-700">Pluriel</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium text-gray-700">Defini</td><td class="p-3 text-center font-bold text-blue-700">des</td><td class="p-3 text-center font-bold text-red-600">der</td><td class="p-3 text-center font-bold text-green-700">des</td><td class="p-3 text-center font-bold text-gray-700">der</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium text-gray-700">Indefini</td><td class="p-3 text-center font-bold text-blue-700">eines</td><td class="p-3 text-center font-bold text-red-600">einer</td><td class="p-3 text-center font-bold text-green-700">eines</td><td class="p-3 text-center text-gray-400">-</td></tr></tbody></table></div><p>Au genitif, les noms masculins et neutres prennent une terminaison <strong>-(e)s</strong> :</p><ul><li><em>der Mann</em> → <em>des Mann<strong>es</strong></em></li><li><em>das Buch</em> → <em>des Buch<strong>es</strong></em></li><li><em>der Vater</em> → <em>des Vater<strong>s</strong></em></li></ul><h2 id="la-possession-avec-le-genitif" tabindex="-1">La possession avec le genitif <a class="header-anchor" href="#la-possession-avec-le-genitif" aria-label="Permalink to “La possession avec le genitif”">​</a></h2><p>Le groupe genitif se place après le nom qu&#39;il qualifie :</p><ul><li><em>das Auto <strong>des Mannes</strong></em> - la voiture de l&#39;homme</li><li><em>der Name <strong>der Stadt</strong></em> - le nom de la ville</li><li><em>die Farbe <strong>des Himmels</strong></em> - la couleur du ciel</li><li><em>das Ende <strong>des Filmes</strong></em> - la fin du film</li></ul><div class="info custom-block"><p class="custom-block-title">Genitif saxon pour les prenoms</p><p>Pour les prenoms et noms propres, on ajoute directement <em>-s</em> sans article : <em>Marias Buch</em> (le livre de Maria), <em>Annas Mutter</em> (la mere d&#39;Anna), <em>Deutschlands Hauptstadt</em> (la capitale de l&#39;Allemagne). Contrairement au français, il n&#39;y a pas d&#39;apostrophe.</p></div><h2 id="von-datif-l-alternative-orale" tabindex="-1">von + datif : l&#39;alternative orale <a class="header-anchor" href="#von-datif-l-alternative-orale" aria-label="Permalink to “von + datif : l&#39;alternative orale”">​</a></h2><p>À l&#39;oral et dans la langue courante, le genitif est souvent remplacé par <em>von + datif</em> :</p><table tabindex="0"><thead><tr><th>Genitif (soutenu)</th><th>von + datif (courant)</th><th>Sens</th></tr></thead><tbody><tr><td><em>das Auto des Mannes</em></td><td><em>das Auto von dem Mann</em></td><td>la voiture de l&#39;homme</td></tr><tr><td><em>der Freund meiner Schwester</em></td><td><em>der Freund von meiner Schwester</em></td><td>l&#39;ami de ma soeur</td></tr></tbody></table><p>Les deux formes sont correctes. En conversation, <em>von + datif</em> est plus naturel. À l&#39;écrit formel ou dans les titres, le genitif est prefere.</p><h2 id="prepositions-genitif" tabindex="-1">Prepositions + genitif <a class="header-anchor" href="#prepositions-genitif" aria-label="Permalink to “Prepositions + genitif”">​</a></h2><p>Ces prépositions exigent toujours le genitif :</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Preposition</th><th class="p-3 text-left font-semibold text-gray-600">Sens</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold text-purple-700">wegen</td><td class="p-3">a cause de</td><td class="p-3 text-gray-500 italic">wegen des Wetters - à cause du temps</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-purple-700">trotz</td><td class="p-3">malgre</td><td class="p-3 text-gray-500 italic">trotz des Regens - malgre la pluie</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-purple-700">wahrend</td><td class="p-3">pendant</td><td class="p-3 text-gray-500 italic">wahrend des Films - pendant le film</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-purple-700">anstatt / statt</td><td class="p-3">au lieu de</td><td class="p-3 text-gray-500 italic">statt des Kaffees - au lieu du cafe</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-purple-700">aufgrund</td><td class="p-3">en raison de</td><td class="p-3 text-gray-500 italic">aufgrund des Problems - en raison du probleme</td></tr></tbody></table></div><div class="tip custom-block"><p class="custom-block-title">wegen moi, wegen toi - la langue parlée utilisé le datif</p><p>Dans la conversation courante, <em>wegen</em> est souvent suivi du datif même si la règle prescrit le genitif : <em>wegen mir</em> (à cause de moi) au lieu de <em>meinetwegen</em> (forme correcte). C&#39;est une evolution de la langue acceptee à l&#39;oral.</p></div><hr><div class="info custom-block"><p class="custom-block-title">Félicitations - tu as complète les cinq modules</p><p>Tu disposes maintenant de toutes les bases grammaticales de l&#39;allemand. La suite, c&#39;est la pratique : ecouter, lire, parler. Consulte la section <a href="/ressources/">Ressources</a> pour aller plus loin.</p></div>',22)])])}const g=t(l,[["render",i]]);export{u as __pageData,g as default};
